const data = $input.first().json.body || $input.first().json;

const rdv = data.rdv;
const client = data.client;
const config = data.config || {};

// Construire les dates ISO pour Google Calendar
const dateDebut = new Date(`${rdv.date}T${rdv.heure}:00`);
const dateFin = new Date(dateDebut.getTime() + (rdv.duree || 60) * 60 * 1000);

const dateDebutFr = dateDebut.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric', timeZone: 'Indian/Reunion' });
const heureDebutFr = dateDebut.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Indian/Reunion' });
const heureFinFr = dateFin.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Indian/Reunion' });

return [{
  json: {
    rdv: {
      ...rdv,
      dateDebutISO: dateDebut.toISOString(),
      dateFinISO: dateFin.toISOString(),
      dateDebutFr,
      heureDebutFr,
      heureFinFr
    },
    client,
    config: {
      calendarId: config.calendarId || 'primary',
      nomEtablissement: config.nomEtablissement || 'Établissement',
      adresse: config.adresse || '',
      couleur: config.couleur || '9', // Vert par défaut
      emailGerant: config.emailGerant || ''
    }
  }
}];
